interface Contato {
  nome: string;
  telefone: string;
  favorito: boolean;
}

const agenda: Contato[] = [
  { nome: "Alice", telefone: "1111-1111", favorito: true },
  { nome: "Bob", telefone: "2222-2222", favorito: false },
  { nome: "Carol", telefone: "3333-3333", favorito: true },
  { nome: "David", telefone: "4444-4444", favorito: false }
];

function listarFavoritos(contatos: Contato[]): void {
  for (const contato of contatos) {
    if (contato.favorito) {
      console.log(`⭐ ${contato.nome} — ${contato.telefone}`);
    }
  }
}

listarFavoritos(agenda);
